import { useStoreSelector } from '../../../../../../core/store/selector.js';
import { AnnotationsStateContext } from '../../contexts/AnnotationsStateContext.js';
import { AnnotationState } from '../../types/state.js';

export const useAnnotationsSelector = <T>(
  selector: (state: AnnotationState) => T,
): T => useStoreSelector(AnnotationsStateContext, selector);

export const useAnnotationsTooltipState = () =>
  useAnnotationsSelector((state: AnnotationState) => state.tooltip);

export const useAnnotationsSelectionState = () =>
  useAnnotationsSelector((state: AnnotationState) => state.selection);
